//===============================================================================================================================================================================================================
//	KERNEL FUNCTION (OpenMP version)
//===============================================================================================================================================================================================================

#include <stdlib.h>
#include <math.h>
#include <string.h>
#include <omp.h>

#include "define.c"

void kernel_function(int bx, params_common common, params_common_change common_change, params_unique* unique_arr) {

    params_unique* u = &unique_arr[bx];

    fp* d_in;
    int rot_row;
    int rot_col;
    int in2_rowlow;
    int in2_collow;
    int ic;
    int jc;
    int jp1;
    int ja1, ja2;
    int ip1;
    int ia1, ia2;
    int ja, jb;
    int ia, ib;
    float s;
    int i;
    int j;
    int row;
    int col;
    int ori_row;
    int ori_col;
    int position;
    float sum;
    int pos_ori;
    float temp;
    float temp2;
    int location;
    int cent;
    int tMask_row;
    int tMask_col;
    float largest_value_current = 0;
    float largest_value = 0;
    int largest_coordinate_current = 0;
    int largest_coordinate = 0;
    float fin_max_val = 0;
    int fin_max_coo = 0;
    int largest_row;
    int largest_col;
    int offset_row;
    int offset_col;
    int pointer;
    int ori_pointer;
    int loc_pointer;
    int ei_new;

    float in_partial_sum[51];
    float in_sqr_partial_sum[51];
    float in_final_sum;
    float in_sqr_final_sum;
    float mean;
    float mean_sqr;
    float variance;
    float deviation;
    float denomT;
    float par_max_val[131];
    int par_max_coo[131];
    float d_in_mod_temp[2601];

    //===============================================================================================================================================================================================================
    //	GENERATE TEMPLATE
    //===============================================================================================================================================================================================================

    if(common_change.frame_no == 0) {

        d_in = &u->d_T[u->in_pointer];

        pointer = u->point_no * common.no_frames + common_change.frame_no;
        u->d_tRowLoc[pointer] = u->d_Row[u->point_no];
        u->d_tColLoc[pointer] = u->d_Col[u->point_no];

        for(ei_new = 0; ei_new < common.in_elem; ei_new++) {
            row = (ei_new+1) % common.in_rows - 1;
            col = (ei_new+1) / common.in_rows + 1 - 1;
            if((ei_new+1) % common.in_rows == 0) {
                row = common.in_rows - 1;
                col = col - 1;
            }
            ori_row = u->d_Row[u->point_no] - 25 + row - 1;
            ori_col = u->d_Col[u->point_no] - 25 + col - 1;
            ori_pointer = ori_col * common.frame_rows + ori_row;
            d_in[col * common.in_rows + row] = common_change.d_frame[ori_pointer];
        }
    }

    //===============================================================================================================================================================================================================
    //	PROCESS POINTS
    //===============================================================================================================================================================================================================

    if(common_change.frame_no != 0) {

        //======================================================================================================================================================
        //	SELECTION
        //======================================================================================================================================================

        in2_rowlow = u->d_Row[u->point_no] - common.sSize;
        in2_collow = u->d_Col[u->point_no] - common.sSize;

        for(ei_new = 0; ei_new < common.in2_elem; ei_new++) {
            row = (ei_new+1) % common.in2_rows - 1;
            col = (ei_new+1) / common.in2_rows + 1 - 1;
            if((ei_new+1) % common.in2_rows == 0) {
                row = common.in2_rows - 1;
                col = col - 1;
            }
            ori_row = row + in2_rowlow - 1;
            ori_col = col + in2_collow - 1;
            u->d_in2[ei_new] = common_change.d_frame[ori_col * common.frame_rows + ori_row];
        }

        //======================================================================================================================================================
        //	CONVOLUTION
        //======================================================================================================================================================

        // ROTATION
        d_in = &u->d_T[u->in_pointer];

        for(ei_new = 0; ei_new < common.in_elem; ei_new++) {
            row = (ei_new+1) % common.in_rows - 1;
            col = (ei_new+1) / common.in_rows + 1 - 1;
            if((ei_new+1) % common.in_rows == 0) {
                row = common.in_rows - 1;
                col = col - 1;
            }
            rot_row = (common.in_rows - 1) - row;
            rot_col = (common.in_rows - 1) - col;
            d_in_mod_temp[ei_new] = d_in[rot_col * common.in_rows + rot_row];
        }

        // ACTUAL CONVOLUTION
        for(ei_new = 0; ei_new < common.conv_elem; ei_new++) {
            ic = (ei_new+1) % common.conv_rows;
            jc = (ei_new+1) / common.conv_rows + 1;
            if((ei_new+1) % common.conv_rows == 0) {
                ic = common.conv_rows;
                jc = jc - 1;
            }

            j = jc + common.joffset;
            jp1 = j + 1;
            if(common.in2_cols < jp1) {
                ja1 = jp1 - common.in2_cols;
            } else {
                ja1 = 1;
            }
            if(common.in_cols < j) {
                ja2 = common.in_cols;
            } else {
                ja2 = j;
            }

            i = ic + common.ioffset;
            ip1 = i + 1;

            if(common.in2_rows < ip1) {
                ia1 = ip1 - common.in2_rows;
            } else {
                ia1 = 1;
            }
            if(common.in_rows < i) {
                ia2 = common.in_rows;
            } else {
                ia2 = i;
            }

            s = 0;
            for(ja = ja1; ja <= ja2; ja++) {
                jb = jp1 - ja;
                for(ia = ia1; ia <= ia2; ia++) {
                    ib = ip1 - ia;
                    s = s + d_in_mod_temp[common.in_rows*(ja-1)+ia-1] * u->d_in2[common.in2_rows*(jb-1)+ib-1];
                }
            }
            u->d_conv[ei_new] = s;
        }

        //======================================================================================================================================================
        //	CUMULATIVE SUM
        //======================================================================================================================================================

        // PAD ARRAY
        for(ei_new = 0; ei_new < common.in2_pad_cumv_elem; ei_new++) {
            row = (ei_new+1) % common.in2_pad_cumv_rows - 1;
            col = (ei_new+1) / common.in2_pad_cumv_rows + 1 - 1;
            if((ei_new+1) % common.in2_pad_cumv_rows == 0) {
                row = common.in2_pad_cumv_rows - 1;
                col = col - 1;
            }
            if( row > (common.in2_pad_add_rows-1) &&
                row < (common.in2_pad_add_rows+common.in2_rows) &&
                col > (common.in2_pad_add_cols-1) &&
                col < (common.in2_pad_add_cols+common.in2_cols)) {
                ori_row = row - common.in2_pad_add_rows;
                ori_col = col - common.in2_pad_add_cols;
                u->d_in2_pad_cumv[ei_new] = u->d_in2[ori_col*common.in2_rows+ori_row];
            } else {
                u->d_in2_pad_cumv[ei_new] = 0;
            }
        }

        // VERTICAL CUMULATIVE SUM
        for(ei_new = 0; ei_new < common.in2_pad_cumv_cols; ei_new++) {
            pos_ori = ei_new * common.in2_pad_cumv_rows;
            sum = 0;
            for(position = pos_ori; position < pos_ori + common.in2_pad_cumv_rows; position++) {
                u->d_in2_pad_cumv[position] = u->d_in2_pad_cumv[position] + sum;
                sum = u->d_in2_pad_cumv[position];
            }
        }

        // SELECTION
        for(ei_new = 0; ei_new < common.in2_pad_cumv_sel_elem; ei_new++) {
            row = (ei_new+1) % common.in2_pad_cumv_sel_rows - 1;
            col = (ei_new+1) / common.in2_pad_cumv_sel_rows + 1 - 1;
            if((ei_new+1) % common.in2_pad_cumv_sel_rows == 0) {
                row = common.in2_pad_cumv_sel_rows - 1;
                col = col - 1;
            }
            ori_row = row + common.in2_pad_cumv_sel_rowlow - 1;
            ori_col = col + common.in2_pad_cumv_sel_collow - 1;
            u->d_in2_pad_cumv_sel[ei_new] = u->d_in2_pad_cumv[ori_col*common.in2_pad_cumv_rows+ori_row];
        }

        // SELECTION 2
        for(ei_new = 0; ei_new < common.in2_sub_cumh_elem; ei_new++) {
            row = (ei_new+1) % common.in2_sub_cumh_rows - 1;
            col = (ei_new+1) / common.in2_sub_cumh_rows + 1 - 1;
            if((ei_new+1) % common.in2_sub_cumh_rows == 0) {
                row = common.in2_sub_cumh_rows - 1;
                col = col - 1;
            }
            ori_row = row + common.in2_pad_cumv_sel2_rowlow - 1;
            ori_col = col + common.in2_pad_cumv_sel2_collow - 1;
            u->d_in2_sub_cumh[ei_new] = u->d_in2_pad_cumv[ori_col*common.in2_pad_cumv_rows+ori_row];
        }

        // SUBTRACTION
        for(ei_new = 0; ei_new < common.in2_sub_cumh_elem; ei_new++) {
            u->d_in2_sub_cumh[ei_new] = u->d_in2_pad_cumv_sel[ei_new] - u->d_in2_sub_cumh[ei_new];
        }

        // HORIZONTAL CUMULATIVE SUM
        for(ei_new = 0; ei_new < common.in2_sub_cumh_rows; ei_new++) {
            pos_ori = ei_new;
            sum = 0;
            for(position = pos_ori; position < pos_ori + common.in2_sub_cumh_elem; position += common.in2_sub_cumh_rows) {
                u->d_in2_sub_cumh[position] = u->d_in2_sub_cumh[position] + sum;
                sum = u->d_in2_sub_cumh[position];
            }
        }

        // SELECTION
        for(ei_new = 0; ei_new < common.in2_sub_cumh_sel_elem; ei_new++) {
            row = (ei_new+1) % common.in2_sub_cumh_sel_rows - 1;
            col = (ei_new+1) / common.in2_sub_cumh_sel_rows + 1 - 1;
            if((ei_new+1) % common.in2_sub_cumh_sel_rows == 0) {
                row = common.in2_sub_cumh_sel_rows - 1;
                col = col - 1;
            }
            ori_row = row + common.in2_sub_cumh_sel_rowlow - 1;
            ori_col = col + common.in2_sub_cumh_sel_collow - 1;
            u->d_in2_sub_cumh_sel[ei_new] = u->d_in2_sub_cumh[ori_col*common.in2_sub_cumh_rows+ori_row];
        }

        // SELECTION 2
        for(ei_new = 0; ei_new < common.in2_sub2_elem; ei_new++) {
            row = (ei_new+1) % common.in2_sub2_rows - 1;
            col = (ei_new+1) / common.in2_sub2_rows + 1 - 1;
            if((ei_new+1) % common.in2_sub2_rows == 0) {
                row = common.in2_sub2_rows - 1;
                col = col - 1;
            }
            ori_row = row + common.in2_sub_cumh_sel2_rowlow - 1;
            ori_col = col + common.in2_sub_cumh_sel2_collow - 1;
            u->d_in2_sub2[ei_new] = u->d_in2_sub_cumh[ori_col*common.in2_sub_cumh_rows+ori_row];
        }

        // SUBTRACTION
        for(ei_new = 0; ei_new < common.in2_sub2_elem; ei_new++) {
            u->d_in2_sub2[ei_new] = u->d_in2_sub_cumh_sel[ei_new] - u->d_in2_sub2[ei_new];
        }

        //======================================================================================================================================================
        //	CUMULATIVE SUM 2
        //======================================================================================================================================================

        // MULTIPLICATION
        for(ei_new = 0; ei_new < common.in2_sqr_elem; ei_new++) {
            temp = u->d_in2[ei_new];
            u->d_in2_sqr[ei_new] = temp * temp;
        }

        // PAD ARRAY
        for(ei_new = 0; ei_new < common.in2_pad_cumv_elem; ei_new++) {
            row = (ei_new+1) % common.in2_pad_cumv_rows - 1;
            col = (ei_new+1) / common.in2_pad_cumv_rows + 1 - 1;
            if((ei_new+1) % common.in2_pad_cumv_rows == 0) {
                row = common.in2_pad_cumv_rows - 1;
                col = col - 1;
            }
            if( row > (common.in2_pad_add_rows-1) &&
                row < (common.in2_pad_add_rows+common.in2_sqr_rows) &&
                col > (common.in2_pad_add_cols-1) &&
                col < (common.in2_pad_add_cols+common.in2_sqr_cols)) {
                ori_row = row - common.in2_pad_add_rows;
                ori_col = col - common.in2_pad_add_cols;
                u->d_in2_pad_cumv[ei_new] = u->d_in2_sqr[ori_col*common.in2_sqr_rows+ori_row];
            } else {
                u->d_in2_pad_cumv[ei_new] = 0;
            }
        }

        // VERTICAL CUMULATIVE SUM
        for(ei_new = 0; ei_new < common.in2_pad_cumv_cols; ei_new++) {
            pos_ori = ei_new * common.in2_pad_cumv_rows;
            sum = 0;
            for(position = pos_ori; position < pos_ori + common.in2_pad_cumv_rows; position++) {
                u->d_in2_pad_cumv[position] = u->d_in2_pad_cumv[position] + sum;
                sum = u->d_in2_pad_cumv[position];
            }
        }

        // SELECTION
        for(ei_new = 0; ei_new < common.in2_pad_cumv_sel_elem; ei_new++) {
            row = (ei_new+1) % common.in2_pad_cumv_sel_rows - 1;
            col = (ei_new+1) / common.in2_pad_cumv_sel_rows + 1 - 1;
            if((ei_new+1) % common.in2_pad_cumv_sel_rows == 0) {
                row = common.in2_pad_cumv_sel_rows - 1;
                col = col - 1;
            }
            ori_row = row + common.in2_pad_cumv_sel_rowlow - 1;
            ori_col = col + common.in2_pad_cumv_sel_collow - 1;
            u->d_in2_pad_cumv_sel[ei_new] = u->d_in2_pad_cumv[ori_col*common.in2_pad_cumv_rows+ori_row];
        }

        // SELECTION 2
        for(ei_new = 0; ei_new < common.in2_sub_cumh_elem; ei_new++) {
            row = (ei_new+1) % common.in2_sub_cumh_rows - 1;
            col = (ei_new+1) / common.in2_sub_cumh_rows + 1 - 1;
            if((ei_new+1) % common.in2_sub_cumh_rows == 0) {
                row = common.in2_sub_cumh_rows - 1;
                col = col - 1;
            }
            ori_row = row + common.in2_pad_cumv_sel2_rowlow - 1;
            ori_col = col + common.in2_pad_cumv_sel2_collow - 1;
            u->d_in2_sub_cumh[ei_new] = u->d_in2_pad_cumv[ori_col*common.in2_pad_cumv_rows+ori_row];
        }

        // SUBTRACTION
        for(ei_new = 0; ei_new < common.in2_sub_cumh_elem; ei_new++) {
            u->d_in2_sub_cumh[ei_new] = u->d_in2_pad_cumv_sel[ei_new] - u->d_in2_sub_cumh[ei_new];
        }

        // HORIZONTAL CUMULATIVE SUM
        for(ei_new = 0; ei_new < common.in2_sub_cumh_rows; ei_new++) {
            pos_ori = ei_new;
            sum = 0;
            for(position = pos_ori; position < pos_ori + common.in2_sub_cumh_elem; position += common.in2_sub_cumh_rows) {
                u->d_in2_sub_cumh[position] = u->d_in2_sub_cumh[position] + sum;
                sum = u->d_in2_sub_cumh[position];
            }
        }

        // SELECTION
        for(ei_new = 0; ei_new < common.in2_sub_cumh_sel_elem; ei_new++) {
            row = (ei_new+1) % common.in2_sub_cumh_sel_rows - 1;
            col = (ei_new+1) / common.in2_sub_cumh_sel_rows + 1 - 1;
            if((ei_new+1) % common.in2_sub_cumh_sel_rows == 0) {
                row = common.in2_sub_cumh_sel_rows - 1;
                col = col - 1;
            }
            ori_row = row + common.in2_sub_cumh_sel_rowlow - 1;
            ori_col = col + common.in2_sub_cumh_sel_collow - 1;
            u->d_in2_sub_cumh_sel[ei_new] = u->d_in2_sub_cumh[ori_col*common.in2_sub_cumh_rows+ori_row];
        }

        // SELECTION 2
        for(ei_new = 0; ei_new < common.in2_sub2_elem; ei_new++) {
            row = (ei_new+1) % common.in2_sub2_rows - 1;
            col = (ei_new+1) / common.in2_sub2_rows + 1 - 1;
            if((ei_new+1) % common.in2_sub2_rows == 0) {
                row = common.in2_sub2_rows - 1;
                col = col - 1;
            }
            ori_row = row + common.in2_sub_cumh_sel2_rowlow - 1;
            ori_col = col + common.in2_sub_cumh_sel2_collow - 1;
            u->d_in2_sqr_sub2[ei_new] = u->d_in2_sub_cumh[ori_col*common.in2_sub_cumh_rows+ori_row];
        }

        // SUBTRACTION
        for(ei_new = 0; ei_new < common.in2_sub2_elem; ei_new++) {
            u->d_in2_sqr_sub2[ei_new] = u->d_in2_sub_cumh_sel[ei_new] - u->d_in2_sqr_sub2[ei_new];
        }

        //======================================================================================================================================================
        //	FINAL
        //======================================================================================================================================================

        // DENOMINATOR A
        for(ei_new = 0; ei_new < common.in2_sub2_elem; ei_new++) {
            temp = u->d_in2_sub2[ei_new];
            temp2 = u->d_in2_sqr_sub2[ei_new] - (temp * temp / common.in_elem);
            if(temp2 < 0) {
                temp2 = 0;
            }
            u->d_in2_sqr_sub2[ei_new] = sqrt(temp2);
        }

        // MULTIPLICATION
        for(ei_new = 0; ei_new < common.in_sqr_elem; ei_new++) {
            temp = d_in[ei_new];
            u->d_in_sqr[ei_new] = temp * temp;
        }

        // IN SUM
        for(ei_new = 0; ei_new < common.in_cols; ei_new++) {
            sum = 0;
            for(i = 0; i < common.in_rows; i++) {
                sum = sum + d_in[ei_new * common.in_rows + i];
            }
            in_partial_sum[ei_new] = sum;
        }

        // IN_SQR SUM
        for(ei_new = 0; ei_new < common.in_sqr_rows; ei_new++) {
            sum = 0;
            for(i = 0; i < common.in_sqr_cols; i++) {
                sum = sum + u->d_in_sqr[ei_new + common.in_sqr_rows * i];
            }
            in_sqr_partial_sum[ei_new] = sum;
        }

        // FINAL SUMMATION
        in_final_sum = 0;
        for(i = 0; i < common.in_cols; i++) {
            in_final_sum = in_final_sum + in_partial_sum[i];
        }

        in_sqr_final_sum = 0;
        for(i = 0; i < common.in_sqr_cols; i++) {
            in_sqr_final_sum = in_sqr_final_sum + in_sqr_partial_sum[i];
        }

        // DENOMINATOR T
        mean = in_final_sum / common.in_elem;
        mean_sqr = mean * mean;
        variance = (in_sqr_final_sum / common.in_elem) - mean_sqr;
        deviation = sqrt(variance);
        denomT = sqrt((float)(common.in_elem - 1)) * deviation;

        // DENOMINATOR
        for(ei_new = 0; ei_new < common.in2_sub2_elem; ei_new++) {
            u->d_in2_sqr_sub2[ei_new] = u->d_in2_sqr_sub2[ei_new] * denomT;
        }

        // NUMERATOR
        for(ei_new = 0; ei_new < common.conv_elem; ei_new++) {
            u->d_conv[ei_new] = u->d_conv[ei_new] - u->d_in2_sub2[ei_new] * in_final_sum / common.in_elem;
        }

        // CORRELATION
        for(ei_new = 0; ei_new < common.in2_sub2_elem; ei_new++) {
            u->d_in2_sqr_sub2[ei_new] = u->d_conv[ei_new] / u->d_in2_sqr_sub2[ei_new];
        }

        //======================================================================================================================================================
        //	TEMPLATE MASK CREATE
        //======================================================================================================================================================

        cent = common.sSize + common.tSize + 1;
        if(common_change.frame_no == 0) {
            tMask_row = cent + u->d_Row[u->point_no] - u->d_Row[u->point_no] - 1;
            tMask_col = cent + u->d_Col[u->point_no] - u->d_Col[u->point_no] - 1;
        } else {
            pointer = common_change.frame_no - 1 + u->point_no * common.no_frames;
            tMask_row = cent + u->d_tRowLoc[pointer] - u->d_Row[u->point_no] - 1;
            tMask_col = cent + u->d_tColLoc[pointer] - u->d_Col[u->point_no] - 1;
        }

        for(ei_new = 0; ei_new < common.tMask_elem; ei_new++) {
            location = tMask_col * common.tMask_rows + tMask_row;
            if(ei_new == location) {
                u->d_tMask[ei_new] = 1;
            } else {
                u->d_tMask[ei_new] = 0;
            }
        }

        //======================================================================================================================================================
        //	MASK CONVOLUTION
        //======================================================================================================================================================

        for(ei_new = 0; ei_new < common.mask_conv_elem; ei_new++) {
            ic = (ei_new+1) % common.mask_conv_rows;
            jc = (ei_new+1) / common.mask_conv_rows + 1;
            if((ei_new+1) % common.mask_conv_rows == 0) {
                ic = common.mask_conv_rows;
                jc = jc - 1;
            }

            j = jc + common.mask_conv_joffset;
            jp1 = j + 1;
            if(common.mask_cols < jp1) {
                ja1 = jp1 - common.mask_cols;
            } else {
                ja1 = 1;
            }
            if(common.tMask_cols < j) {
                ja2 = common.tMask_cols;
            } else {
                ja2 = j;
            }

            i = ic + common.mask_conv_ioffset;
            ip1 = i + 1;

            if(common.mask_rows < ip1) {
                ia1 = ip1 - common.mask_rows;
            } else {
                ia1 = 1;
            }
            if(common.tMask_rows < i) {
                ia2 = common.tMask_rows;
            } else {
                ia2 = i;
            }

            s = 0;
            for(ja = ja1; ja <= ja2; ja++) {
                jb = jp1 - ja;
                for(ia = ia1; ia <= ia2; ia++) {
                    ib = ip1 - ia;
                    s = s + u->d_tMask[common.tMask_rows*(ja-1)+ia-1] * 1;
                }
            }
            u->d_mask_conv[ei_new] = u->d_in2_sqr_sub2[ei_new] * s;
        }

        //======================================================================================================================================================
        //	MAXIMUM VALUE
        //======================================================================================================================================================

        // INITIAL SEARCH
        for(ei_new = 0; ei_new < common.mask_conv_rows; ei_new++) {
            float lv = 0;
            int lc = 0;
            for(i = 0; i < common.mask_conv_cols; i++) {
                largest_coordinate_current = ei_new * common.mask_conv_rows + i;
                largest_value_current = fabsf(u->d_mask_conv[largest_coordinate_current]);
                if(largest_value_current > lv) {
                    lc = largest_coordinate_current;
                    lv = largest_value_current;
                }
            }
            par_max_coo[ei_new] = lc;
            par_max_val[ei_new] = lv;
        }

        // FINAL SEARCH
        fin_max_val = 0;
        fin_max_coo = 0;
        for(i = 0; i < common.mask_conv_rows; i++) {
            if(par_max_val[i] > fin_max_val) {
                fin_max_val = par_max_val[i];
                fin_max_coo = par_max_coo[i];
            }
        }

        // convert coordinate to row/col form
        largest_row = (fin_max_coo+1) % common.mask_conv_rows - 1;
        largest_col = (fin_max_coo+1) / common.mask_conv_rows;
        if((fin_max_coo+1) % common.mask_conv_rows == 0) {
            largest_row = common.mask_conv_rows - 1;
            largest_col = largest_col - 1;
        }

        largest_row = largest_row + 1;
        largest_col = largest_col + 1;
        offset_row = largest_row - common.in_rows - (common.sSize - common.tSize);
        offset_col = largest_col - common.in_cols - (common.sSize - common.tSize);
        pointer = common_change.frame_no + u->point_no * common.no_frames;
        u->d_tRowLoc[pointer] = u->d_Row[u->point_no] + offset_row;
        u->d_tColLoc[pointer] = u->d_Col[u->point_no] + offset_col;
    }

    //===============================================================================================================================================================================================================
    //	COORDINATE AND TEMPLATE UPDATE
    //===============================================================================================================================================================================================================

    if(common_change.frame_no != 0 && (common_change.frame_no) % 10 == 0) {

        loc_pointer = u->point_no * common.no_frames + common_change.frame_no;
        u->d_Row[u->point_no] = u->d_tRowLoc[loc_pointer];
        u->d_Col[u->point_no] = u->d_tColLoc[loc_pointer];

        for(ei_new = 0; ei_new < common.in_elem; ei_new++) {
            row = (ei_new+1) % common.in_rows - 1;
            col = (ei_new+1) / common.in_rows + 1 - 1;
            if((ei_new+1) % common.in_rows == 0) {
                row = common.in_rows - 1;
                col = col - 1;
            }
            ori_row = u->d_Row[u->point_no] - 25 + row - 1;
            ori_col = u->d_Col[u->point_no] - 25 + col - 1;
            ori_pointer = ori_col * common.frame_rows + ori_row;
            d_in[ei_new] = common.alpha * d_in[ei_new] + (1.00 - common.alpha) * common_change.d_frame[ori_pointer];
        }
    }
}

void kernel_launch(params_common common, params_common_change common_change, params_unique* unique_arr) {
    int bx;
    #pragma omp parallel for schedule(dynamic,1)
    for(bx = 0; bx < common.allPoints; bx++) {
        kernel_function(bx, common, common_change, unique_arr);
    }
}

