#include "define.c"

extern params_common common;
extern params_common_change common_change;
extern params_unique punt[ALL_POINTS];

void kernel_function(int bx) {

    fp* d_in;
    int rot_row;
    int rot_col;
    int in2_rowlow;
    int in2_collow;
    int ic;
    int jc;
    int jp1;
    int ja1, ja2;
    int ip1;
    int ia1, ia2;
    int ja, jb;
    int ia, ib;
    float s;
    int i;
    int j;
    int row;
    int col;
