    float in_sqr_partial_sum[51];
    float in_final_sum;
    float in_sqr_final_sum;
    float mean;
    float mean_sqr;
    float variance;
    float deviation;
    float denomT;
    float par_max_val[131];
    int   par_max_coo[131];
