    //===============================================================================

    if (common_change.frame_no == 0) {

        d_in = &punt[bx].d_T[punt[bx].in_pointer];

        // Update row/col loc
        pointer = punt[bx].point_no * common.no_frames + common_change.frame_no;
        punt[bx].d_tRowLoc[pointer] = punt[bx].d_Row[punt[bx].point_no];
        punt[bx].d_tColLoc[pointer] = punt[bx].d_Col[punt[bx].point_no];

        // Create templates
        ei_new = 0;
        while (ei_new < common.in_elem) {
            row = (ei_new + 1) % common.in_rows - 1;
            col = (ei_new + 1) / common.in_rows + 1 - 1;
            if ((ei_new + 1) % common.in_rows == 0) {
                row = common.in_rows - 1;
                col = col - 1;
            }

            ori_row = punt[bx].d_Row[punt[bx].point_no] - 25 + row - 1;
            ori_col = punt[bx].d_Col[punt[bx].point_no] - 25 + col - 1;
            ori_pointer = ori_col * common.frame_rows + ori_row;

            d_in[col * common.in_rows + row] = common_change.d_frame[ori_pointer];

            ei_new = ei_new + 1;
        }
    }

    //===============================================================================
    // PROCESS POINTS
    //===============================================================================

    if (common_change.frame_no != 0) {

        //==========================================================================
        // SELECTION
        //==========================================================================

        in2_rowlow = punt[bx].d_Row[punt[bx].point_no] - common.sSize;
        in2_collow = punt[bx].d_Col[punt[bx].point_no] - common.sSize;

        ei_new = 0;
        while (ei_new < common.in2_elem) {
            row = (ei_new + 1) % common.in2_rows - 1;
            col = (ei_new + 1) / common.in2_rows + 1 - 1;
            if ((ei_new + 1) % common.in2_rows == 0) {
                row = common.in2_rows - 1;
                col = col - 1;
            }

            ori_row = row + in2_rowlow - 1;
            ori_col = col + in2_collow - 1;
            punt[bx].d_in2[ei_new] = common_change.d_frame[ori_col * common.frame_rows + ori_row];

            ei_new = ei_new + 1;
        }

        //==========================================================================
        // CONVOLUTION
        //==========================================================================

        // ROTATION
        d_in = &punt[bx].d_T[punt[bx].in_pointer];

        ei_new = 0;
        while (ei_new < common.in_elem) {
            row = (ei_new + 1) % common.in_rows - 1;
            col = (ei_new + 1) / common.in_rows + 1 - 1;
            if ((ei_new + 1) % common.in_rows == 0) {
                row = common.in_rows - 1;
                col = col - 1;
            }

            rot_row = (common.in_rows - 1) - row;
            rot_col = (common.in_rows - 1) - col;
            d_in_mod_temp[ei_new] = d_in[rot_col * common.in_rows + rot_row];

            ei_new = ei_new + 1;
        }

        // ACTUAL CONVOLUTION
        ei_new = 0;
        while (ei_new < common.conv_elem) {
            ic = (ei_new + 1) % common.conv_rows;
            jc = (ei_new + 1) / common.conv_rows + 1;
            if ((ei_new + 1) % common.conv_rows == 0) {
                ic = common.conv_rows;
                jc -= 1;
            }

            j = jc + common.joffset;
            jp1 = j + 1;
            if (common.in2_cols < jp1) {
                ja1 = jp1 - common.in2_cols;
            } else {
                ja1 = 1;
            }
            if (common.in_cols < j) {
                ja2 = common.in_cols;
            } else {
                ja2 = j;
            }

            i = ic + common.ioffset;
            ip1 = i + 1;

            if (common.in2_rows < ip1) {
                ia1 = ip1 - common.in2_rows;
            } else {
                ia1 = 1;
            }
            if (common.in_rows < i) {
                ia2 = common.in_rows;
            } else {
                ia2 = i;
            }

            s = 0;
            for (ja = ja1; ja <= ja2; ja++) {
                jb = jp1 - ja;
                for (ia = ia1; ia <= ia2; ia++) {
                    ib = ip1 - ia;
                    s = s + d_in_mod_temp[common.in_rows * (ja - 1) + ia - 1] * punt[bx].d_in2[common.in2_rows * (jb - 1) + ib - 1];
                }
            }

            punt[bx].d_conv[ei_new] = s;

            ei_new = ei_new + 1;
        }

        //==========================================================================
        // CUMULATIVE SUM
        //==========================================================================

        // PAD ARRAY
        ei_new = 0;
        while (ei_new < common.in2_pad_cumv_elem) {
            row = (ei_new + 1) % common.in2_pad_cumv_rows - 1;
            col = (ei_new + 1) / common.in2_pad_cumv_rows + 1 - 1;
            if ((ei_new + 1) % common.in2_pad_cumv_rows == 0) {
                row = common.in2_pad_cumv_rows - 1;
                col = col - 1;
            }

            if (row > (common.in2_pad_add_rows - 1) &&
                row < (common.in2_pad_add_rows + common.in2_rows) &&
                col > (common.in2_pad_add_cols - 1) &&
                col < (common.in2_pad_add_cols + common.in2_cols)) {
                ori_row = row - common.in2_pad_add_rows;
                ori_col = col - common.in2_pad_add_cols;
                punt[bx].d_in2_pad_cumv[ei_new] = punt[bx].d_in2[ori_col * common.in2_rows + ori_row];
            } else {
                punt[bx].d_in2_pad_cumv[ei_new] = 0;
            }

            ei_new = ei_new + 1;
        }

        // VERTICAL CUMULATIVE SUM
        ei_new = 0;
        while (ei_new < common.in2_pad_cumv_cols) {
            pos_ori = ei_new * common.in2_pad_cumv_rows;
            sum = 0;
            for (position = pos_ori; position < pos_ori + common.in2_pad_cumv_rows; position += 1) {
                punt[bx].d_in2_pad_cumv[position] = punt[bx].d_in2_pad_cumv[position] + sum;
                sum = punt[bx].d_in2_pad_cumv[position];
            }
            ei_new = ei_new + 1;
        }

        // SELECTION
        ei_new = 0;
        while (ei_new < common.in2_pad_cumv_sel_elem) {
            row = (ei_new + 1) % common.in2_pad_cumv_sel_rows - 1;
            col = (ei_new + 1) / common.in2_pad_cumv_sel_rows + 1 - 1;
            if ((ei_new + 1) % common.in2_pad_cumv_sel_rows == 0) {
                row = common.in2_pad_cumv_sel_rows - 1;
                col -= 1;
            }

            ori_row = row + common.in2_pad_cumv_sel_rowlow - 1;
            ori_col = col + common.in2_pad_cumv_sel_collow - 1;
            punt[bx].d_in2_pad_cumv_sel[ei_new] = punt[bx].d_in2_pad_cumv[ori_col * common.in2_pad_cumv_rows + ori_row];

            ei_new = ei_new + 1;
        }

        // SELECTION 2
        ei_new = 0;
        while (ei_new < common.in2_sub_cumh_elem) {
            row = (ei_new + 1) % common.in2_sub_cumh_rows - 1;
            col = (ei_new + 1) / common.in2_sub_cumh_rows + 1 - 1;
            if ((ei_new + 1) % common.in2_sub_cumh_rows == 0) {
                row = common.in2_sub_cumh_rows - 1;
                col -= 1;
            }

            ori_row = row + common.in2_pad_cumv_sel2_rowlow - 1;
            ori_col = col + common.in2_pad_cumv_sel2_collow - 1;
            punt[bx].d_in2_sub_cumh[ei_new] = punt[bx].d_in2_pad_cumv[ori_col * common.in2_pad_cumv_rows + ori_row];

            ei_new = ei_new + 1;
        }

        // SUBTRACTION
        ei_new = 0;
        while (ei_new < common.in2_sub_cumh_elem) {
            punt[bx].d_in2_sub_cumh[ei_new] = punt[bx].d_in2_pad_cumv_sel[ei_new] - punt[bx].d_in2_sub_cumh[ei_new];
            ei_new = ei_new + 1;
        }

        // HORIZONTAL CUMULATIVE SUM
        ei_new = 0;
        while (ei_new < common.in2_sub_cumh_rows) {
            pos_ori = ei_new;
            sum = 0;
            for (position = pos_ori; position < pos_ori + common.in2_sub_cumh_elem; position = position + common.in2_sub_cumh_rows) {
                punt[bx].d_in2_sub_cumh[position] = punt[bx].d_in2_sub_cumh[position] + sum;
                sum = punt[bx].d_in2_sub_cumh[position];
            }
            ei_new = ei_new + 1;
        }

        // SELECTION
        ei_new = 0;
        while (ei_new < common.in2_sub_cumh_sel_elem) {
            row = (ei_new + 1) % common.in2_sub_cumh_sel_rows - 1;
            col = (ei_new + 1) / common.in2_sub_cumh_sel_rows + 1 - 1;
            if ((ei_new + 1) % common.in2_sub_cumh_sel_rows == 0) {
                row = common.in2_sub_cumh_sel_rows - 1;
                col -= 1;
            }

            ori_row = row + common.in2_sub_cumh_sel_rowlow - 1;
            ori_col = col + common.in2_sub_cumh_sel_collow - 1;
            punt[bx].d_in2_sub_cumh_sel[ei_new] = punt[bx].d_in2_sub_cumh[ori_col * common.in2_sub_cumh_rows + ori_row];

            ei_new = ei_new + 1;
        }

        // SELECTION 2
        ei_new = 0;
        while (ei_new < common.in2_sub2_elem) {
            row = (ei_new + 1) % common.in2_sub2_rows - 1;
            col = (ei_new + 1) / common.in2_sub2_rows + 1 - 1;
            if ((ei_new + 1) % common.in2_sub2_rows == 0) {
                row = common.in2_sub2_rows - 1;
                col = col - 1;
            }

            ori_row = row + common.in2_sub_cumh_sel2_rowlow - 1;
            ori_col = col + common.in2_sub_cumh_sel2_collow - 1;
            punt[bx].d_in2_sub2[ei_new] = punt[bx].d_in2_sub_cumh[ori_col * common.in2_sub_cumh_rows + ori_row];

            ei_new = ei_new + 1;
        }

        // SUBTRACTION
        ei_new = 0;
        while (ei_new < common.in2_sub2_elem) {
            punt[bx].d_in2_sub2[ei_new] = punt[bx].d_in2_sub_cumh_sel[ei_new] - punt[bx].d_in2_sub2[ei_new];
            ei_new = ei_new + 1;
        }

        //==========================================================================
        // CUMULATIVE SUM 2
        //==========================================================================

        // MULTIPLICATION
        ei_new = 0;
        while (ei_new < common.in2_sqr_elem) {
            temp = punt[bx].d_in2[ei_new];
            punt[bx].d_in2_sqr[ei_new] = temp * temp;
            ei_new = ei_new + 1;
        }

        // PAD ARRAY
        ei_new = 0;
        while (ei_new < common.in2_pad_cumv_elem) {
            row = (ei_new + 1) % common.in2_pad_cumv_rows - 1;
            col = (ei_new + 1) / common.in2_pad_cumv_rows + 1 - 1;
            if ((ei_new + 1) % common.in2_pad_cumv_rows == 0) {
                row = common.in2_pad_cumv_rows - 1;
                col = col - 1;
            }

            if (row > (common.in2_pad_add_rows - 1) &&
                row < (common.in2_pad_add_rows + common.in2_sqr_rows) &&
                col > (common.in2_pad_add_cols - 1) &&
                col < (common.in2_pad_add_cols + common.in2_sqr_cols)) {
                ori_row = row - common.in2_pad_add_rows;
                ori_col = col - common.in2_pad_add_cols;
                punt[bx].d_in2_pad_cumv[ei_new] = punt[bx].d_in2_sqr[ori_col * common.in2_sqr_rows + ori_row];
            } else {
                punt[bx].d_in2_pad_cumv[ei_new] = 0;
            }

            ei_new = ei_new + 1;
        }

        // VERTICAL CUMULATIVE SUM
        ei_new = 0;
        while (ei_new < common.in2_pad_cumv_cols) {
            pos_ori = ei_new * common.in2_pad_cumv_rows;
            sum = 0;
            for (position = pos_ori; position < pos_ori + common.in2_pad_cumv_rows; position += 1) {
                punt[bx].d_in2_pad_cumv[position] = punt[bx].d_in2_pad_cumv[position] + sum;
                sum = punt[bx].d_in2_pad_cumv[position];
            }
            ei_new = ei_new + 1;
        }

        // SELECTION
        ei_new = 0;
        while (ei_new < common.in2_pad_cumv_sel_elem) {
            row = (ei_new + 1) % common.in2_pad_cumv_sel_rows - 1;
            col = (ei_new + 1) / common.in2_pad_cumv_sel_rows + 1 - 1;
            if ((ei_new + 1) % common.in2_pad_cumv_sel_rows == 0) {
                row = common.in2_pad_cumv_sel_rows - 1;
                col -= 1;
            }

            ori_row = row + common.in2_pad_cumv_sel_rowlow - 1;
            ori_col = col + common.in2_pad_cumv_sel_collow - 1;
            punt[bx].d_in2_pad_cumv_sel[ei_new] = punt[bx].d_in2_pad_cumv[ori_col * common.in2_pad_cumv_rows + ori_row];

            ei_new = ei_new + 1;
        }

        // SELECTION 2
        ei_new = 0;
        while (ei_new < common.in2_sub_cumh_elem) {
            row = (ei_new + 1) % common.in2_sub_cumh_rows - 1;
            col = (ei_new + 1) / common.in2_sub_cumh_rows + 1 - 1;
            if ((ei_new + 1) % common.in2_sub_cumh_rows == 0) {
                row = common.in2_sub_cumh_rows - 1;
                col -= 1;
            }

            ori_row = row + common.in2_pad_cumv_sel2_rowlow - 1;
            ori_col = col + common.in2_pad_cumv_sel2_collow - 1;
            punt[bx].d_in2_sub_cumh[ei_new] = punt[bx].d_in2_pad_cumv[ori_col * common.in2_pad_cumv_rows + ori_row];

            ei_new = ei_new + 1;
        }

        // SUBTRACTION
        ei_new = 0;
        while (ei_new < common.in2_sub_cumh_elem) {
            punt[bx].d_in2_sub_cumh[ei_new] = punt[bx].d_in2_pad_cumv_sel[ei_new] - punt[bx].d_in2_sub_cumh[ei_new];
            ei_new = ei_new + 1;
        }

        // HORIZONTAL CUMULATIVE SUM
        ei_new = 0;
        while (ei_new < common.in2_sub_cumh_rows) {
            pos_ori = ei_new;
            sum = 0;
            for (position = pos_ori; position < pos_ori + common.in2_sub_cumh_elem; position = position + common.in2_sub_cumh_rows) {
                punt[bx].d_in2_sub_cumh[position] = punt[bx].d_in2_sub_cumh[position] + sum;
                sum = punt[bx].d_in2_sub_cumh[position];
            }
            ei_new = ei_new + 1;
        }

        // SELECTION
        ei_new = 0;
        while (ei_new < common.in2_sub_cumh_sel_elem) {
            row = (ei_new + 1) % common.in2_sub_cumh_sel_rows - 1;
            col = (ei_new + 1) / common.in2_sub_cumh_sel_rows + 1 - 1;
            if ((ei_new + 1) % common.in2_sub_cumh_sel_rows == 0) {
                row = common.in2_sub_cumh_sel_rows - 1;
                col -= 1;
            }

            ori_row = row + common.in2_sub_cumh_sel_rowlow - 1;
            ori_col = col + common.in2_sub_cumh_sel_collow - 1;
            punt[bx].d_in2_sub_cumh_sel[ei_new] = punt[bx].d_in2_sub_cumh[ori_col * common.in2_sub_cumh_rows + ori_row];

            ei_new = ei_new + 1;
        }

        // SELECTION 2
        ei_new = 0;
        while (ei_new < common.in2_sub2_elem) {
            row = (ei_new + 1) % common.in2_sub2_rows - 1;
            col = (ei_new + 1) / common.in2_sub2_rows + 1 - 1;
            if ((ei_new + 1) % common.in2_sub2_rows == 0) {
                row = common.in2_sub2_rows - 1;
                col = col - 1;
            }

            ori_row = row + common.in2_sub_cumh_sel2_rowlow - 1;
            ori_col = col + common.in2_sub_cumh_sel2_collow - 1;
            punt[bx].d_in2_sqr_sub2[ei_new] = punt[bx].d_in2_sub_cumh[ori_col * common.in2_sub_cumh_rows + ori_row];

            ei_new = ei_new + 1;
        }

        // SUBTRACTION
        ei_new = 0;
        while (ei_new < common.in2_sub2_elem) {
            punt[bx].d_in2_sqr_sub2[ei_new] = punt[bx].d_in2_sub_cumh_sel[ei_new] - punt[bx].d_in2_sqr_sub2[ei_new];
            ei_new = ei_new + 1;
        }

        //==========================================================================
        // FINAL
        //==========================================================================

        // DENOMINATOR A
        ei_new = 0;
        while (ei_new < common.in2_sub2_elem) {
            temp = punt[bx].d_in2_sub2[ei_new];
            temp2 = punt[bx].d_in2_sqr_sub2[ei_new] - (temp * temp / common.in_elem);
            if (0 > temp2) {
                temp2 = 0;
            }
            punt[bx].d_in2_sqr_sub2[ei_new] = sqrt(temp2);
            ei_new = ei_new + 1;
        }

        // MULTIPLICATION
        ei_new = 0;
        while (ei_new < common.in_sqr_elem) {
            temp = d_in[ei_new];
            punt[bx].d_in_sqr[ei_new] = temp * temp;
            ei_new = ei_new + 1;
        }

        // IN SUM
        ei_new = 0;
        while (ei_new < common.in_cols) {
            sum = 0;
            for (i = 0; i < common.in_rows; i++) {
                sum = sum + d_in[ei_new * common.in_rows + i];
            }
            in_partial_sum[ei_new] = sum;
            ei_new = ei_new + 1;
        }

        // IN_SQR SUM
        ei_new = 0;
        while (ei_new < common.in_sqr_rows) {
            sum = 0;
            for (i = 0; i < common.in_sqr_cols; i++) {
                sum = sum + punt[bx].d_in_sqr[ei_new + common.in_sqr_rows * i];
            }
            in_sqr_partial_sum[ei_new] = sum;
            ei_new = ei_new + 1;
        }

        // FINAL SUMMATION
        in_final_sum = 0;
        for (i = 0; i < common.in_cols; i++) {
            in_final_sum = in_final_sum + in_partial_sum[i];
        }

        in_sqr_final_sum = 0;
        for (i = 0; i < common.in_sqr_cols; i++) {
            in_sqr_final_sum = in_sqr_final_sum + in_sqr_partial_sum[i];
        }

        // DENOMINATOR T
        mean = in_final_sum / common.in_elem;
        mean_sqr = mean * mean;
        variance = (in_sqr_final_sum / common.in_elem) - mean_sqr;
        deviation = sqrt(variance);
        denomT = sqrt((float)(common.in_elem - 1)) * deviation;

        // DENOMINATOR
        ei_new = 0;
        while (ei_new < common.in2_sub2_elem) {
            punt[bx].d_in2_sqr_sub2[ei_new] = punt[bx].d_in2_sqr_sub2[ei_new] * denomT;
            ei_new = ei_new + 1;
        }

        // NUMERATOR
        ei_new = 0;
        while (ei_new < common.conv_elem) {
            punt[bx].d_conv[ei_new] = punt[bx].d_conv[ei_new] - punt[bx].d_in2_sub2[ei_new] * in_final_sum / common.in_elem;
            ei_new = ei_new + 1;
        }

        // CORRELATION
        ei_new = 0;
        while (ei_new < common.in2_sub2_elem) {
            punt[bx].d_in2_sqr_sub2[ei_new] = punt[bx].d_conv[ei_new] / punt[bx].d_in2_sqr_sub2[ei_new];
            ei_new = ei_new + 1;
        }

        //==========================================================================
        // TEMPLATE MASK CREATE
        //==========================================================================

        cent = common.sSize + common.tSize + 1;
        if (common_change.frame_no == 0) {
            tMask_row = cent + punt[bx].d_Row[punt[bx].point_no] - punt[bx].d_Row[punt[bx].point_no] - 1;
            tMask_col = cent + punt[bx].d_Col[punt[bx].point_no] - punt[bx].d_Col[punt[bx].point_no] - 1;
        } else {
            pointer = common_change.frame_no - 1 + punt[bx].point_no * common.no_frames;
            tMask_row = cent + punt[bx].d_tRowLoc[pointer] - punt[bx].d_Row[punt[bx].point_no] - 1;
            tMask_col = cent + punt[bx].d_tColLoc[pointer] - punt[bx].d_Col[punt[bx].point_no] - 1;
        }

        ei_new = 0;
        while (ei_new < common.tMask_elem) {
            location = tMask_col * common.tMask_rows + tMask_row;
            if (location == ei_new) {
                punt[bx].d_tMask[ei_new] = 1;
            } else {
                punt[bx].d_tMask[ei_new] = 0;
            }
            ei_new = ei_new + 1;
        }

        //==========================================================================
        // MASK CONVOLUTION
        //==========================================================================

        ei_new = 0;
        while (ei_new < common.mask_conv_elem) {
            ic = (ei_new + 1) % common.mask_conv_rows;
            jc = (ei_new + 1) / common.mask_conv_rows + 1;
            if ((ei_new + 1) % common.mask_conv_rows == 0) {
                ic = common.mask_conv_rows;
                jc -= 1;
            }

            j = jc + common.mask_conv_joffset;
            jp1 = j + 1;
            if (common.mask_cols < jp1) {
                ja1 = jp1 - common.mask_cols;
            } else {
                ja1 = 1;
            }
            if (common.tMask_cols < j) {
                ja2 = common.tMask_cols;
            } else {
                ja2 = j;
            }

            i = ic + common.mask_conv_ioffset;
            ip1 = i + 1;

            if (common.mask_rows < ip1) {
                ia1 = ip1 - common.mask_rows;
            } else {
                ia1 = 1;
            }
            if (common.tMask_rows < i) {
                ia2 = common.tMask_rows;
            } else {
                ia2 = i;
            }

            s = 0;
            for (ja = ja1; ja2 >= ja; ja++) {
                jb = jp1 - ja;
                for (ia = ia1; ia <= ia2; ia++) {
                    ib = ip1 - ia;
                    s = s + punt[bx].d_tMask[common.tMask_rows * (ja - 1) + ia - 1] * 1;
                }
            }

            punt[bx].d_mask_conv[ei_new] = punt[bx].d_in2_sqr_sub2[ei_new] * s;

            ei_new = ei_new + 1;
        }

        //==========================================================================
        // MAXIMUM VALUE
        //==========================================================================

        // INITIAL SEARCH
        for (ei_new = 0; ei_new < common.mask_conv_rows; ei_new++) {
            largest_value = 0;
            largest_coordinate = 0;
            for (i = 0; i < common.mask_conv_cols; i++) {
                largest_coordinate_current = ei_new * common.mask_conv_rows + i;
                largest_value_current = fabs(punt[bx].d_mask_conv[largest_coordinate_current]);
                if (largest_value < largest_value_current) {
                    largest_coordinate = largest_coordinate_current;
                    largest_value = largest_value_current;
                }
            }
            par_max_coo[ei_new] = largest_coordinate;
            par_max_val[ei_new] = largest_value;
        }

        // FINAL SEARCH
        fin_max_val = 0;
        fin_max_coo = 0;
        for (i = 0; i < common.mask_conv_rows; i++) {
            if (fin_max_val < par_max_val[i]) {
                fin_max_val = par_max_val[i];
                fin_max_coo = par_max_coo[i];
            }
        }

        // convert coordinate to row/col form
