        punt[bx].d_tRowLoc[pointer] = punt[bx].d_Row[punt[bx].point_no] + offset_row;
        punt[bx].d_tColLoc[pointer] = punt[bx].d_Col[punt[bx].point_no] + offset_col;

    } // end if frame_no != 0

    //===============================================================================
    // COORDINATE AND TEMPLATE UPDATE
    //===============================================================================

    if (common_change.frame_no != 0 && (common_change.frame_no) % 10 == 0) {

        loc_pointer = punt[bx].point_no * common.no_frames + common_change.frame_no;
        punt[bx].d_Row[punt[bx].point_no] = punt[bx].d_tRowLoc[loc_pointer];
        punt[bx].d_Col[punt[bx].point_no] = punt[bx].d_tColLoc[loc_pointer];

        d_in = &punt[bx].d_T[punt[bx].in_pointer];

        ei_new = 0;
        while (ei_new < common.in_elem) {
            row = (ei_new + 1) % common.in_rows - 1;
            col = (ei_new + 1) / common.in_rows + 1 - 1;
            if ((ei_new + 1) % common.in_rows == 0) {
