            ori_col = punt[bx].d_Col[punt[bx].point_no] - 25 + col - 1;
            ori_pointer = ori_col * common.frame_rows + ori_row;

            d_in[ei_new] = common.alpha * d_in[ei_new] + (1.00 - common.alpha) * common_change.d_frame[ori_pointer];

            ei_new = ei_new + 1;
        }
    }
}

void kernel_launch(void) {
    int bx;
    #pragma omp parallel for schedule(dynamic,1)
    for (bx = 0; bx < common.allPoints; bx++) {
        kernel_function(bx);
    }
}

