void hotspot_opt1(float *p, float *tIn, float *tOut,
        int nx, int ny, int nz,
        float Cap,
        float Rx, float Ry, float Rz,
        float dt, int numiter)
{
    float ce, cw, cn, cs, ct, cb, cc;
    float stepDivCap = dt / Cap;
    ce = cw = stepDivCap / Rx;
    cn = cs = stepDivCap / Ry;
    ct = cb = stepDivCap / Rz;

    cc = 1.0 - (2.0 * ce + 2.0 * cn + 3.0 * ct);

    int xy = nx * ny;

    long long start = get_time();

    for (int iter = 0; iter < numiter; ++iter) {
        #pragma omp parallel for collapse(2) schedule(static)
        for (int j = 0; j < ny; j++) {
            for (int i = 0; i < nx; i++) {
                int c = i + j * nx;

                int W = (i == 0)      ? c : c - 1;
                int E = (i == nx - 1) ? c : c + 1;
                int N = (j == 0)      ? c : c - nx;
                int S = (j == ny - 1) ? c : c + nx;

                float temp1, temp2, temp3;
                temp1 = temp2 = tIn[c];
                temp3 = tIn[c + xy];
                tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
                    + cn * tIn[N] + cb * temp1 + ct * temp3 + stepDivCap * p[c] + ct * amb_temp;

                int cc_idx = c + xy;
                int W_idx = W + xy;
                int E_idx = E + xy;
                int N_idx = N + xy;
                int S_idx = S + xy;

                for (int k = 1; k < nz - 1; ++k) {
                    temp1 = temp2;
                    temp2 = temp3;
                    temp3 = tIn[cc_idx + xy];
                    tOut[cc_idx] = cc * temp2 + cw * tIn[W_idx] + ce * tIn[E_idx] + cs * tIn[S_idx]
                        + cn * tIn[N_idx] + cb * temp1 + ct * temp3 + stepDivCap * p[cc_idx] + ct * amb_temp;
                    cc_idx += xy;
                    W_idx += xy;
                    E_idx += xy;
                    N_idx += xy;
                    S_idx += xy;
                }
                temp1 = temp2;
                temp2 = temp3;
                tOut[cc_idx] = cc * temp2 + cw * tIn[W_idx] + ce * tIn[E_idx] + cs * tIn[S_idx]
                    + cn * tIn[N_idx] + cb * temp1 + ct * temp3 + stepDivCap * p[cc_idx] + ct * amb_temp;
            }
        }

        /* swap tIn and tOut */
        float *t = tIn;
        tIn = tOut;
        tOut = t;
    }

    long long stop = get_time();
    float time = (float)((stop - start) / (1000.0 * 1000.0));
    printf("Time: %.3f (s)\n", time);

    /* After numiter swaps, tIn holds the result; copy back to tOut */
    /* Because we swapped, tIn is the result and tOut is the old tIn */
    /* We need to copy tIn back to the original tOut pointer */
    /* But since we swapped pointers locally, we need to copy tIn to tOut */
    memcpy(tOut, tIn, sizeof(float) * nx * ny * nz);
}

void computeTempCPU(float *pIn, float *tIn, float *tOut,
        int nx, int ny, int nz, float Cap,
        float Rx, float Ry, float Rz,
        float dt, int numiter)
{
    float ce, cw, cn, cs, ct, cb, cc;
    float stepDivCap = dt / Cap;
    ce = cw = stepDivCap / Rx;
    cn = cs = stepDivCap / Ry;
    ct = cb = stepDivCap / Rz;

    cc = 1.0 - (2.0 * ce + 2.0 * cn + 3.0 * ct);

    int c, w, e, n, s, b, t;
    int x, y, z;
    int i = 0;
    do {
        for (z = 0; z < nz; z++)
            for (y = 0; y < ny; y++)
                for (x = 0; x < nx; x++) {
                    c = x + y * nx + z * nx * ny;

                    w = (x == 0)      ? c : c - 1;
                    e = (x == nx - 1) ? c : c + 1;
                    n = (y == 0)      ? c : c - nx;
                    s = (y == ny - 1) ? c : c + nx;
                    b = (z == 0)      ? c : c - nx * ny;
                    t = (z == nz - 1) ? c : c + nx * ny;

                    tOut[c] = tIn[c] * cc + tIn[n] * cn + tIn[s] * cs + tIn[e] * ce + tIn[w] * cw + tIn[t] * ct + tIn[b] * cb + (dt / Cap) * pIn[c] + ct * amb_temp;
                }
        float *temp = tIn;
        tIn = tOut;
        tOut = temp;
        i++;
    } while (i < numiter);
}

float accuracy(float *arr1, float *arr2, int len)
{
    float err = 0.0;
