void hotspot_opt1(float *p, float *tIn, float *tOut,
        int nx, int ny, int nz,
        float Cap,
        float Rx, float Ry, float Rz,
        float dt, int numiter)
{
    float ce, cw, cn, cs, ct, cb, cc;
    float stepDivCap = dt / Cap;
    ce = cw = stepDivCap / Rx;
    cn = cs = stepDivCap / Ry;
    ct = cb = stepDivCap / Rz;

    cc = 1.0 - (2.0 * ce + 2.0 * cn + 3.0 * ct);

    int size = nx * ny * nz;
    float *tIn_buf = (float *)malloc(size * sizeof(float));
    float *tOut_buf = (float *)malloc(size * sizeof(float));
    memcpy(tIn_buf, tIn, size * sizeof(float));

    int xy = nx * ny;

    long long start = get_time();

    for (int iter = 0; iter < numiter; ++iter) {
        #pragma omp parallel for collapse(2) schedule(static)
        for (int j = 0; j < ny; j++) {
            for (int i = 0; i < nx; i++) {
                int c = i + j * nx;

                int W = (i == 0) ? c : c - 1;
                int E = (i == nx - 1) ? c : c + 1;
                int N = (j == 0) ? c : c - nx;
                int S = (j == ny - 1) ? c : c + nx;

                float temp1, temp2, temp3;
                temp1 = temp2 = tIn_buf[c];
                temp3 = tIn_buf[c + xy];
                tOut_buf[c] = cc * temp2 + cw * tIn_buf[W] + ce * tIn_buf[E] + cs * tIn_buf[S]
                    + cn * tIn_buf[N] + cb * temp1 + ct * temp3 + stepDivCap * p[c] + ct * amb_temp;

                int c2 = c + xy;
                int W2 = W + xy;
                int E2 = E + xy;
                int N2 = N + xy;
                int S2 = S + xy;

                for (int k = 1; k < nz - 1; ++k) {
                    temp1 = temp2;
                    temp2 = temp3;
                    temp3 = tIn_buf[c2 + xy];
                    tOut_buf[c2] = cc * temp2 + cw * tIn_buf[W2] + ce * tIn_buf[E2] + cs * tIn_buf[S2]
                        + cn * tIn_buf[N2] + cb * temp1 + ct * temp3 + stepDivCap * p[c2] + ct * amb_temp;
                    c2 += xy;
                    W2 += xy;
                    E2 += xy;
                    N2 += xy;
                    S2 += xy;
                }
                temp1 = temp2;
                temp2 = temp3;
                tOut_buf[c2] = cc * temp2 + cw * tIn_buf[W2] + ce * tIn_buf[E2] + cs * tIn_buf[S2]
                    + cn * tIn_buf[N2] + cb * temp1 + ct * temp3 + stepDivCap * p[c2] + ct * amb_temp;
            }
        }

        float *t = tIn_buf;
        tIn_buf = tOut_buf;
        tOut_buf = t;
    }

    long long stop = get_time();
    float time = (float)((stop - start) / (1000.0 * 1000.0));
    printf("Time: %.3f (s)\n", time);

