        /* Actually redo this properly matching the CUDA kernel logic */
        /* The CUDA kernel does:
           for each i from 0 to BLOCK_SIZE-2:
             for threadIdx.x > i: shadow[threadIdx.x][i] -= sum; shadow[threadIdx.x][i] /= diag
             sync
             for threadIdx.x > i: shadow[i+1][threadIdx.x] -= sum (U row update for row i+1)
             sync
        */
    }

    /* Redo with correct algorithm matching CUDA kernel */
    /* Reset shadow */
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            shadow[i][j] = m[(offset + i) * matrix_dim + offset + j];
        }
    }

    for (i = 0; i < BLOCK_SIZE - 1; i++) {
        /* Update column i for rows > i (L part) */
        for (j = i + 1; j < BLOCK_SIZE; j++) {
            float val = shadow[j][i];
            for (int k = 0; k < i; k++)
                val -= shadow[j][k] * shadow[k][i];
            shadow[j][i] = val / shadow[i][i];
        }
        /* Update row i+1 for columns > i (U part) */
        for (j = i + 1; j < BLOCK_SIZE; j++) {
            float val = shadow[i + 1][j];
            for (int k = 0; k < i + 1; k++)
                val -= shadow[i + 1][k] * shadow[k][j];
            shadow[i + 1][j] = val;
        }
    }

    /* Write back (skip first row as in CUDA) */
    for (i = 1; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            m[(offset + i) * matrix_dim + offset + j] = shadow[i][j];
        }
    }
}

static void lud_perimeter(float *m, int matrix_dim, int offset, int num_blocks)
{
    int bx;

    #pragma omp parallel for num_threads(omp_num_threads) schedule(dynamic)
    for (bx = 0; bx < num_blocks; bx++) {
        int i, j;
        float dia[BLOCK_SIZE][BLOCK_SIZE];
        float peri_row[BLOCK_SIZE][BLOCK_SIZE];
        float peri_col[BLOCK_SIZE][BLOCK_SIZE];

        /* Load diagonal block */
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                dia[i][j] = m[(offset + i) * matrix_dim + offset + j];
            }
        }

        /* Load peri_row block: row block at (offset, offset + (bx+1)*BLOCK_SIZE) */
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                peri_row[i][j] = m[(offset + i) * matrix_dim + offset + (bx + 1) * BLOCK_SIZE + j];
            }
        }

        /* Load peri_col block: col block at (offset + (bx+1)*BLOCK_SIZE, offset) */
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                peri_col[i][j] = m[(offset + (bx + 1) * BLOCK_SIZE + i) * matrix_dim + offset + j];
            }
        }

        /* Update peri_row: forward substitution using dia (L part) */
        for (i = 1; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                for (int k = 0; k < i; k++) {
                    peri_row[i][j] -= dia[i][k] * peri_row[k][j];
                }
            }
        }

        /* Update peri_col: forward substitution using dia (U part) */
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                for (int k = 0; k < i; k++) {
                    peri_col[j][i] -= peri_col[j][k] * dia[k][i];
                }
                peri_col[j][i] /= dia[i][i];
            }
        }

        /* Write back peri_row (skip first row) */
        for (i = 1; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                m[(offset + i) * matrix_dim + offset + (bx + 1) * BLOCK_SIZE + j] = peri_row[i][j];
            }
        }

        /* Write back peri_col */
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                m[(offset + (bx + 1) * BLOCK_SIZE + i) * matrix_dim + offset + j] = peri_col[i][j];
            }
        }
    }
}

static void lud_internal(float *m, int matrix_dim, int offset, int num_blocks)
{
    int by, bx;

    #pragma omp parallel for collapse(2) num_threads(omp_num_threads) schedule(dynamic)
    for (by = 0; by < num_blocks; by++) {
        for (bx = 0; bx < num_blocks; bx++) {
            int i, j, k;
            float peri_row[BLOCK_SIZE][BLOCK_SIZE];
            float peri_col[BLOCK_SIZE][BLOCK_SIZE];

            int global_row_id = offset + (by + 1) * BLOCK_SIZE;
            int global_col_id = offset + (bx + 1) * BLOCK_SIZE;

            /* Load peri_row: row at (offset, global_col_id) */
            for (i = 0; i < BLOCK_SIZE; i++) {
                for (j = 0; j < BLOCK_SIZE; j++) {
                    peri_row[i][j] = m[(offset + i) * matrix_dim + global_col_id + j];
                }
            }

            /* Load peri_col: col at (global_row_id, offset) */
            for (i = 0; i < BLOCK_SIZE; i++) {
                for (j = 0; j < BLOCK_SIZE; j++) {
                    peri_col[i][j] = m[(global_row_id + i) * matrix_dim + offset + j];
                }
            }

            /* Update internal block */
            for (i = 0; i < BLOCK_SIZE; i++) {
                for (j = 0; j < BLOCK_SIZE; j++) {
                    float sum = 0.0f;
                    for (k = 0; k < BLOCK_SIZE; k++) {
                        sum += peri_col[i][k] * peri_row[k][j];
                    }
                    m[(global_row_id + i) * matrix_dim + global_col_id + j] -= sum;
                }
            }
        }
    }
}

void lud_omp(float *m, int matrix_dim)
{
    int i;

    for (i = 0; i < matrix_dim - BLOCK_SIZE; i += BLOCK_SIZE) {
        lud_diagonal(m, matrix_dim, i);
        int num_blocks = (matrix_dim - i) / BLOCK_SIZE - 1;
        lud_perimeter(m, matrix_dim, i, num_blocks);
        lud_internal(m, matrix_dim, i, num_blocks);
    }
    lud_diagonal(m, matrix_dim, i);
}

