extern int omp_num_threads;

static void lud_diagonal(float *m, int matrix_dim, int offset)
{
    int i, j, k;
    int block_size = BLOCK_SIZE;

    /* Process the diagonal block */
    for (i = offset; i < offset + block_size; i++) {
        /* Update U part: row i, columns i..offset+block_size-1 */
        for (j = i; j < offset + block_size; j++) {
            float sum = m[i * matrix_dim + j];
            for (k = offset; k < i; k++) {
                sum -= m[i * matrix_dim + k] * m[k * matrix_dim + j];
            }
            m[i * matrix_dim + j] = sum;
        }
        /* Update L part: rows i+1..offset+block_size-1, column i */
        for (j = i + 1; j < offset + block_size; j++) {
            float sum = m[j * matrix_dim + i];
            for (k = offset; k < i; k++) {
                sum -= m[j * matrix_dim + k] * m[k * matrix_dim + i];
            }
            m[j * matrix_dim + i] = sum / m[i * matrix_dim + i];
        }
    }
}

static void lud_perimeter(float *m, int matrix_dim, int offset)
{
    int i, j, k;
    int block_size = BLOCK_SIZE;
    int num_blocks = (matrix_dim - offset) / block_size - 1;

    /* Update perimeter row blocks (U part) */
    #pragma omp parallel for num_threads(omp_num_threads) schedule(static)
    for (int b = 0; b < num_blocks; b++) {
        int col_offset = offset + (b + 1) * block_size;
        /* For each row in the diagonal block */
        for (i = offset; i < offset + block_size; i++) {
            /* Update row i, columns col_offset..col_offset+block_size-1 */
            for (j = col_offset; j < col_offset + block_size; j++) {
                float sum = m[i * matrix_dim + j];
                for (k = offset; k < i; k++) {
                    sum -= m[i * matrix_dim + k] * m[k * matrix_dim + j];
                }
                m[i * matrix_dim + j] = sum;
            }
        }
    }

    /* Update perimeter column blocks (L part) */
    #pragma omp parallel for num_threads(omp_num_threads) schedule(static)
    for (int b = 0; b < num_blocks; b++) {
        int row_offset = offset + (b + 1) * block_size;
        /* For each column in the diagonal block */
        for (j = offset; j < offset + block_size; j++) {
            /* Update rows row_offset..row_offset+block_size-1, column j */
            for (i = row_offset; i < row_offset + block_size; i++) {
                float sum = m[i * matrix_dim + j];
                for (k = offset; k < j; k++) {
                    sum -= m[i * matrix_dim + k] * m[k * matrix_dim + j];
                }
                m[i * matrix_dim + j] = sum / m[j * matrix_dim + j];
            }
        }
    }
}

static void lud_internal(float *m, int matrix_dim, int offset)
{
    int i, j, k;
    int block_size = BLOCK_SIZE;
    int num_blocks = (matrix_dim - offset) / block_size - 1;

    #pragma omp parallel for num_threads(omp_num_threads) collapse(2) schedule(static)
    for (int br = 0; br < num_blocks; br++) {
        for (int bc = 0; bc < num_blocks; bc++) {
            int row_offset = offset + (br + 1) * block_size;
            int col_offset = offset + (bc + 1) * block_size;

            for (i = row_offset; i < row_offset + block_size; i++) {
                for (j = col_offset; j < col_offset + block_size; j++) {
                    float sum = 0.0f;
                    for (k = offset; k < offset + block_size; k++) {
                        sum += m[i * matrix_dim + k] * m[k * matrix_dim + j];
                    }
                    m[i * matrix_dim + j] -= sum;
                }
            }
        }
    }
}

void lud_omp(float *m, int matrix_dim)
{
    int i;
    for (i = 0; i < matrix_dim - BLOCK_SIZE; i += BLOCK_SIZE) {
        lud_diagonal(m, matrix_dim, i);
        lud_perimeter(m, matrix_dim, i);
        lud_internal(m, matrix_dim, i);
    }
    lud_diagonal(m, matrix_dim, i);
}

