static inline void set_result(unsigned int cur,
                   _MatchCoord* result, 
                   int edge_match_length,
                   int qry_match_len,
                   int min_match_len,
                   int rc_flag)
{
  if (qry_match_len > min_match_len)
  {
    edge_match_length |= rc_flag;
    result->node = (int)cur;
    result->edge_match_length = edge_match_length;
  }
}

#define SET_RESULT(c, r, e, q, m, rc) set_result(c, r, e, q, m, rc)

static inline int _min(int x, int y) { return x < y ? x : y; }
static inline int _max(int x, int y) { return x < y ? y : x; }

void mummergpuKernel_omp(void* match_coords,
                char* queries_base,
                _PixelOfNode* nodes,
                _PixelOfChildren* childrenarr,
                char* ref,
                const int* queryAddrs,
                const int* queryLengths,
                const int numQueries,
                const int min_match_len)
{
    #pragma omp parallel for schedule(dynamic, 1)
    for (int qryid = 0; qryid < numQueries; qryid++)
    {
        int qlen = queryLengths[qryid];
        int qryAddr = queryAddrs[qryid];

        unsigned int cur = 0;

        int mustmatch = 0;
        int qry_match_len = 0;

        _MatchCoord * result = (_MatchCoord*)match_coords + qryAddr - (qryid * (min_match_len + 1));

        char* queries = queries_base + qryAddr;

        int last = qlen - min_match_len;
        for (int qrystart = 0;
                 qrystart <= last;
                 qrystart++, 
                 result += RESULT_SPAN) 
        {
            unsigned int node_start = 0;
            unsigned int prev = 0;

            if ((cur == 0) || (qry_match_len < 1)) 
            {
                GOROOT(cur);
                qry_match_len = 1;
                mustmatch = 0;
            }

            char c = queries[qrystart + qry_match_len];

            unsigned int refpos = 0;
            while ((c != '\0')) 
            {
                _PixelOfChildren children;
                children = GETCHILDRENHIST(cur, false);
                prev = cur;
                unsigned int next_addr = 0;
                switch (c) 
                {
                    case 'A': arrayToAddress(children.a, next_addr); break;
                    case 'C': arrayToAddress(children.c, next_addr); break;
                    case 'G': arrayToAddress(children.g, next_addr); break;
                    case 'T': arrayToAddress(children.t, next_addr); break;
                    default: next_addr = 0; break;
                };
                cur = next_addr;

                if (cur == 0) {
                    SET_RESULT(prev, result, 0, qry_match_len, min_match_len, FORWARD);

                    qry_match_len -= 1;
                    mustmatch = 0;

                    goto NEXT_SUBSTRING;
                }

                _PixelOfNode node;
                node = GETNODEHIST(cur, true);
                node_start = MKI3(node.start);
                unsigned int node_end = MKI3(node.end);

                {
                    int edgelen = node_end - node_start + 1;
                    int edge_matchlen = node_start + mustmatch;
                    int past_node_end = node_end + 1;
                    int dist_to_edge_end = mustmatch - edgelen;
                    if (mustmatch) {
                        refpos = (unsigned int)_min(edge_matchlen, past_node_end);
                        qry_match_len += _min(edgelen, mustmatch);
                        mustmatch = _max(dist_to_edge_end, 0);
                    }
                    else {
                        qry_match_len++;
                        refpos = node_start + 1;
                    }
                }

                c = queries[qrystart + qry_match_len];

                while (refpos <= node_end && c != '\0') 
                {
                    char r = GETRCHAR(refpos);

                    if (r != c) 
                    {
                        goto RECORD_RESULT;
                    }

                    qry_match_len++;
                    refpos++;

                    c = queries[qrystart + qry_match_len];
                }
            }

RECORD_RESULT:
            {
                SET_RESULT(cur, result, (int)refpos - (int)node_start, qry_match_len,
                           min_match_len, FORWARD);

                mustmatch = (int)refpos - (int)node_start;
                qry_match_len -= mustmatch + 1;
            }
NEXT_SUBSTRING:
            {
                _PixelOfNode node;
                node = GETNODEHIST(prev, false);
                arrayToAddress(node.suffix, cur);
            }
            do {} while (0);
        }
    }
}

void printKernel_omp(MatchInfo * matches,
            int totalMatches,
            Alignment * alignments,
            char * queries_base,
            _PixelOfNode* nodes,
            _PixelOfChildren* childrenarr,
            const int * queryAddrs,
            const int * queryLengths,
            const int page_begin,
            const int page_end,
            const int page_shadow_left,
            const int page_shadow_right,
            const int min_match_length)
{
  (void)queryLengths;
  #pragma omp parallel for schedule(dynamic, 1)
  for (int matchid = 0; matchid < totalMatches; matchid++)
  {
    int qryAddr = queryAddrs[matches[matchid].queryid];
    char* queries = queries_base + qryAddr;

    char queryflankingbase = queries[matches[matchid].qrystartpos];

    unsigned int matchaddr = matches[matchid].matchnode.data;
    unsigned int cur = matchaddr;
    unsigned int printParent = cur;

    _PixelOfNode node;
    node = GETNODE(cur, true);

    while (MKI3(node.depth) > min_match_length)
    {
      printParent = cur;
      arrayToAddress(node.parent, cur);
      node = GETNODE(cur, true);
    }

    unsigned int badParent = cur;
    cur = printParent;

    char curchild = 'A';
    bool forceToParent = false;

    node = GETNODE(printParent, true);

    int matchlen = MKI3(node.depth) - 1;
    int depthToGoldenPath = 0;

    int matchnum = matches[matchid].resultsoffset;

    if (printParent == matchaddr)
    {
      if (matches[matchid].edgematch > 0)
      {
        node = GETNODE(badParent, true);
        matchlen = MKI3(node.depth)-1+matches[matchid].edgematch;
      }

      depthToGoldenPath = 1;
    }

    while (cur != badParent)
    {
      _PixelOfChildren children;
      children = GETCHILDREN(cur, true);
      char isLeaf = children.leafchar;

      if (isLeaf || forceToParent)
      {
        if (isLeaf && isLeaf != queryflankingbase)
        {
          int leafid = MKI3(children.leafid);
          int left_in_ref = (leafid - 1) + page_begin; 
          int right_in_ref = left_in_ref + matchlen;

          if ((left_in_ref != page_begin || page_shadow_left == -1) && 
              (right_in_ref != page_end || page_shadow_right == -1))
          {
            if (!(left_in_ref > page_begin && right_in_ref < page_shadow_left))
            {
              alignments[matchnum].left_in_ref = left_in_ref;
              alignments[matchnum].matchlen = (unsigned short)matchlen;
              matchnum++;
            }
          }
        }

        forceToParent = false;

        node = GETNODE(cur, true);

        unsigned int myParent;
        arrayToAddress(node.parent, myParent);

        _PixelOfChildren pchildren;
        pchildren = GETCHILDREN(myParent, true);

        unsigned int pa, pc, pg, pt;
        arrayToAddress(pchildren.a, pa);
        arrayToAddress(pchildren.c, pc);
        arrayToAddress(pchildren.g, pg);
        arrayToAddress(pchildren.t, pt);

        if      (pa == cur) { curchild = 'C'; }
        else if (pc == cur) { curchild = 'G'; }
        else if (pg == cur) { curchild = 'T'; }
        else if (pt == cur) { curchild = '$'; }
        else
        {
          forceToParent = true;
        }

        cur = myParent;

        if (depthToGoldenPath) { depthToGoldenPath--; }

        if (depthToGoldenPath == 0)
        {
          node = GETNODE(cur, true);
          matchlen = MKI3(node.depth)-1;
        }
      }
      else
      {
        _PixelOfChildren children2;
        children2 = GETCHILDREN(cur, true);

        char goldenChild = 0;

        if (depthToGoldenPath == 0)
        {
          goldenChild = queries[matches[matchid].qrystartpos+matchlen+1];
        }

        do
        {
          if (curchild == 'A')
          {
            if (children2.a[0] || children2.a[1] || children2.a[2])
            { 
              arrayToAddress(children2.a, cur);
              break; 
            }
            curchild = 'C';
          }

          if (curchild == 'C')
          {
            if (children2.c[0] || children2.c[1] || children2.c[2])
            { 
              arrayToAddress(children2.c, cur); 
              break; 
            }
            curchild = 'G';
          }

          if (curchild == 'G')
          {
            if (children2.g[0] || children2.g[1] || children2.g[2])
            { 
              arrayToAddress(children2.g, cur); 
              break; 
            }
            curchild = 'T';
          }

          if (curchild == 'T')
          {
            if (children2.t[0] || children2.t[1] || children2.t[2])
            { 
              arrayToAddress(children2.t, cur); 
              break; 
            }
            curchild = '$';
          }

          if (curchild == '$')
          {
            if (children2.d[0] || children2.d[1] || children2.d[2])
            { 
              arrayToAddress(children2.d, cur); 
              break; 
            }
          }

          forceToParent = true;
        } 
        while (0);

        if (!forceToParent)
        {
          if (depthToGoldenPath == 0)
          {
            if (curchild == goldenChild)
            {
              node = GETNODE(cur, true);
              matchlen = MKI3(node.depth)-1;

              if (cur == matchaddr)
              {
                depthToGoldenPath = 1;

                if (matches[matchid].edgematch > 0)
                {
                  unsigned int par;
                  arrayToAddress(node.parent, par);

                  node = GETNODE(par, true);
                  matchlen = MKI3(node.depth) - 1 + matches[matchid].edgematch;
                }
              }
            }
            else
            {
              depthToGoldenPath = 1;
            }
          }
          else
          {
            depthToGoldenPath++;
          }

          curchild = 'A';
        }
      }
    }
  }
}

#endif // #ifndef _MUMMERGPU_KERNEL_H_

