void set_result(unsigned int cur,
					   MatchCoord* result, 
					   int edge_match_length,
                       int qry_match_len,
                       int min_match_len,
                       int rc
                       )
{
  if (qry_match_len > min_match_len)
  {
    edge_match_length |= rc;
	result->node.data = cur;
	result->edge_match_length = edge_match_length;
  }
  else
