#else
    return addr;
#endif
}

static inline TextureAddress id2addr(int id)
{
    TextureAddress retval;
    retval.data = 0;

#if REORDER_TREE
    int bigx = id & 0x1FFFF;
    int bigy = id >> 17;
    retval.y = (bigy << 5) + (bigx & 0x1F);
    retval.x = bigx >> 5;
#else
    retval.x = id;
#endif
    return retval;
}

#define MKI(uc3) (uc3.x | (uc3.y << 8) | (uc3.z << 16))

static inline void arrayToAddress(uchar3 arr, unsigned int& addr)
{
#if REORDER_TREE
  addr = (arr.x | ((arr.z & 0xF) << 8)) | ((arr.y | ((arr.z & 0xF0) << 4)) << 16); 
#else
  addr = arr.x | (arr.y << 8) | (arr.z << 16);
#endif
}

static inline char getRef(int refpos, char* ref)
{
    return ref[refpos];
}

static inline char rc(char c)
{
  switch(c)
  {
    case 'A': return 'T';
    case 'C': return 'G';
    case 'G': return 'C';
    case 'T': return 'A';
    case 'q': return '\0';
    default:  return c;
  };
}

static inline uint4 getNode(unsigned int cur, 
                          bool /*use_two_level*/,
                          _PixelOfNode* nodes
                         ) 
{
#if REORDER_TREE
  return (nodes + (cur & 0x0000FFFF) + (((cur & 0xFFFF0000)>>16) * MAX_TEXTURE_DIMENSION))->data;
#else
  return (nodes + cur)->data;
#endif
}

static inline uint4 getChildren(unsigned int cur, 
                              bool /*use_two_level*/,
                          _PixelOfChildren* childrenarr
                          )
{
#if REORDER_TREE
  return (childrenarr +  (cur & 0x0000FFFF) + (((cur & 0xFFFF0000)>>16) * MAX_TEXTURE_DIMENSION))->data;
#else
  return (childrenarr + cur)->data;
#endif
}

#define SET_RESULT(c, r, e, q, m, rc) set_result(c, r, e, q, m, rc)

static inline void set_result(unsigned int cur,
                   _MatchCoord* result, 
                   int edge_match_length,
                   int qry_match_len,
                   int min_match_len,
                   int rc_flag
                   )
{
  if (min_match_len < qry_match_len)
  {
    edge_match_length = edge_match_length | (rc_flag);
    result->data.x = cur;
    result->data.y = edge_match_length;
  }
}

static inline int imin(int a, int b) { return a < b ? a : b; }
static inline int imax(int a, int b) { return a > b ? a : b; }

static void mummergpuKernelSingle(
    int qryid,
    void* match_coords,
    char* queries_base,
    _PixelOfNode* nodes,
    _PixelOfChildren* childrenarr,
    char* ref,
    const int* queryAddrs,
    const int* queryLengths,
    const int numQueries,
    const int min_match_len
)
{
    if (numQueries <= qryid) { return; }

    int qlen = queryLengths[qryid];
    int qryAddr = queryAddrs[qryid];

    unsigned int cur = 0;

    int mustmatch = 0;
    int qry_match_len = 0;

    _MatchCoord * result = MATCH_BASE(match_coords, qryid);

    char* queries = queries_base + qryAddr;

    int last = qlen - min_match_len;
    for (int qrystart = 0;
             last >= qrystart;
             qrystart++, 
             result += RESULT_SPAN) 
    {
        unsigned int node_start = 0;
        unsigned int prev = 0;

        if ((0 == cur) || (1 > qry_match_len)) 
        {
            GOROOT(cur);
            qry_match_len = 1;
            mustmatch = 0;
        }

        char c = GETQCHAR(qrystart + qry_match_len);

        unsigned int refpos = 0;
        while (('\0' != c)) 
        {
            _PixelOfChildren children;
            children.data = GETCHILDRENHIST(cur, false);
            prev = cur;
            uchar3 next;
            switch (c) 
            {
                case 'A': next = children.a; break;
                case 'C': next = children.c; break;
                case 'G': next = children.g; break;
                case 'T': next = children.t; break;
                default: next.x = 0; next.y = 0; next.z = 0; break;
            };

            arrayToAddress(next, cur);

            if (0 == cur) {
                SET_RESULT(prev, result, 0, qry_match_len, min_match_len, FORWARD);

                qry_match_len = qry_match_len - (1);
                mustmatch = 0;

                goto NEXT_SUBSTRING;
            }

            _PixelOfNode node;
            node.data = GETNODEHIST(cur, true);
            node_start = MKI(node.start);
            unsigned int node_end = MKI(node.end);

            {
                int edgelen = node_end - node_start + 1;
                int edge_matchlen = node_start + mustmatch;
                int past_node_end = node_end + 1;
                int dist_to_edge_end = mustmatch - edgelen;
                if (mustmatch) {
                    refpos = imin(edge_matchlen, past_node_end);
                    qry_match_len = qry_match_len + (imin(edgelen, mustmatch));
                    mustmatch = imax(dist_to_edge_end, 0);
                }
                else {
                    qry_match_len++;
                    refpos = node_start + 1;
                }
            }

            c = GETQCHAR(qrystart + qry_match_len);

            while (node_end >= refpos && '\0' != c) 
            {
                char r = GETRCHAR(refpos);

                if (c != r) 
                {
                    goto RECORD_RESULT;
                }

                qry_match_len++;
                refpos++;

                c = GETQCHAR(qrystart + qry_match_len);
            }
        }

RECORD_RESULT:
        {
            SET_RESULT(cur, result, refpos - node_start, qry_match_len,
                       min_match_len, FORWARD);

            mustmatch = refpos - node_start;
            qry_match_len = qry_match_len - (mustmatch + 1);
        }
NEXT_SUBSTRING:
        {
            _PixelOfNode node;
            node.data = GETNODEHIST(prev, false);
            arrayToAddress(node.suffix, cur);
        }
        do {} while (0);
    }

    return;
}

static void printKernelSingle(
    int matchid,
    MatchInfo * matches,
    int totalMatches,
    Alignment * alignments,
    char * queries_base,
    _PixelOfNode* nodes,
    _PixelOfChildren* childrenarr,
    const int * queryAddrs,
    const int * /*queryLengths*/,
    const int page_begin,
    const int page_end,
    const int page_shadow_left,
    const int page_shadow_right,
    const int min_match_length
)
{
  if (totalMatches <= matchid) { return; }

  int qryAddr = queryAddrs[matches[matchid].queryid];

  char* queries = queries_base + qryAddr;

  char queryflankingbase = GETQCHAR(matches[matchid].qrystartpos);

  unsigned int matchaddr = matches[matchid].matchnode.data;
  unsigned int cur = matchaddr;
  unsigned int printParent = cur;

  _PixelOfNode node;
  node.data = GETNODE(cur, true);

  while (min_match_length < (int)MKI(node.depth))
  {
    printParent = cur;
    arrayToAddress(node.parent, cur);
    node.data = GETNODE(cur, true);
  }

  unsigned int badParent = cur;
  cur = printParent;

  char curchild = 'A';
  bool forceToParent = false;

  node.data = GETNODE(printParent, true);

  int matchlen = MKI(node.depth) - 1;
  int depthToGoldenPath = 0;

  int matchnum = matches[matchid].resultsoffset;

  if (matchaddr == printParent)
  {
    if (0 < matches[matchid].edgematch)
    {
      node.data = GETNODE(badParent, true);
      matchlen = MKI(node.depth)-1+matches[matchid].edgematch;
    }

    depthToGoldenPath = 1;
  }

  while (badParent != cur)
  {
    _PixelOfChildren children;
    children.data = GETCHILDREN(cur, true);
    char isLeaf = children.leafchar;

    if (isLeaf || forceToParent)
    {
      if (isLeaf && queryflankingbase != isLeaf)
      {
        int leafid = MKI(children.leafid);
        int left_in_ref = (leafid - 1) + page_begin; 
        int right_in_ref = left_in_ref + matchlen;

        if ((page_begin != left_in_ref || -1 == page_shadow_left) && 
            (page_end != right_in_ref || -1 == page_shadow_right))
        {
          if (!(page_begin < left_in_ref && page_shadow_left > right_in_ref))
          {
            alignments[matchnum].left_in_ref = left_in_ref;
            alignments[matchnum].matchlen = matchlen;
            matchnum++;
          }
        }
      }

      forceToParent = false;

      node.data = GETNODE(cur, true);

      unsigned int myParent;
      arrayToAddress(node.parent, myParent);

      _PixelOfChildren pchildren;
      pchildren.data = GETCHILDREN(myParent, true);

      unsigned int pa, pc, pg, pt;
      arrayToAddress(pchildren.a, pa);
      arrayToAddress(pchildren.c, pc);
      arrayToAddress(pchildren.g, pg);
      arrayToAddress(pchildren.t, pt);

      if      (cur == pa) { curchild = 'C'; }
      else if (cur == pc) { curchild = 'G'; }
      else if (cur == pg) { curchild = 'T'; }
      else if (cur == pt) { curchild = '$'; }
      else
      {
        forceToParent = true;
      }

      cur = myParent;

      if (depthToGoldenPath) { depthToGoldenPath--; }

      if (0 == depthToGoldenPath)
      {
        node.data = GETNODE(cur, true);
        matchlen = MKI(node.depth)-1;
      }
    }
    else
    {
      _PixelOfChildren children2;
      children2.data = GETCHILDREN(cur, true);

      char goldenChild = 0;

      if (0 == depthToGoldenPath)
      {
        goldenChild = GETQCHAR(matches[matchid].qrystartpos+matchlen+1);
      }

      do
      {
        if ('A' == curchild)
        {
          if (children2.a.x || children2.a.y || children2.a.z)
          { 
            arrayToAddress(children2.a, cur);
            break; 
          }

          curchild = 'C';
        }

        if ('C' == curchild)
        {
          if (children2.c.x || children2.c.y || children2.c.z)
          { 
            arrayToAddress(children2.c, cur); 
            break; 
          }
          curchild = 'G';
        }

        if ('G' == curchild)
        {
          if (children2.g.x || children2.g.y || children2.g.z)
          { 
            arrayToAddress(children2.g, cur); 
            break; 
          }
          curchild = 'T';
        }

        if ('T' == curchild)
        {
          if (children2.t.x || children2.t.y || children2.t.z)
          { 
            arrayToAddress(children2.t, cur); 
            break; 
          }
          curchild = '$';
        }

        if ('$' == curchild)
        {
          if (children2.d.x || children2.d.y || children2.d.z)
          { 
            arrayToAddress(children2.d, cur); 
            break; 
          }
        }

        forceToParent = true;
      } 
      while (0);

      if (!forceToParent)
      {
        if (0 == depthToGoldenPath)
        {
          if (goldenChild == curchild)
          {
            node.data = GETNODE(cur, true);
            matchlen = MKI(node.depth)-1;

            if (matchaddr == cur)
            {
              depthToGoldenPath = 1;

              if (0 < matches[matchid].edgematch)
              {
                unsigned int par;
                arrayToAddress(node.parent, par);

                node.data = GETNODE(par, true);
                matchlen = MKI(node.depth) - 1 + matches[matchid].edgematch;
              }
            }
          }
          else
          {
            depthToGoldenPath = 1;
          }
        }
        else
        {
          depthToGoldenPath++;
        }

        curchild = 'A';
      }
    }
  }
}

#endif // #ifndef _MUMMERGPU_KERNEL_H_

