translated_files.file.c:
#include <stdio.h>
#include "define.c"

void write_data(char* filename,
                fp* input,
                int data_rows,
                int data_cols,
                int major,
                int data_range){
    FILE* fid;
    int i, j;
    fid = fopen(filename, "w");
    if(fid == NULL){
        printf("The file was not created/opened for writing\n");
        return;
    }
    if(major==0){
        for(i=0; i<data_rows; i++){
            for(j=0; j<data_cols; j++){
                fprintf(fid, "%f ", (fp)input[i*data_cols+j]);
            }
            fprintf(fid, "\n");
        }
    }
    else{
        for(i=0; i<data_rows; i++){
            for(j=0; j<data_cols; j++){
                fprintf(fid, "%f ", (fp)input[j*data_rows+i]);
            }
            fprintf(fid, "\n");
        }
    }
    fclose(fid);
}

void read(char* filename,
          fp* input,
          int data_rows,
          int data_cols,
          int major){
    FILE* fid;
    int i, j;
    fp temp;
    fid = fopen(filename, "r");
    if(fid == NULL){
        printf("The file was not opened for reading\n");
        return;
    }
    if(major==0){
        for(i=0; i<data_rows; i++){
            for(j=0; j<data_cols; j++){
                if(fscanf(fid, "%f", &temp) == 1)
                    input[i*data_cols+j] = (fp)temp;
            }
        }
    }
    else{
        for(i=0; i<data_rows; i++){
            for(j=0; j<data_cols; j++){
                if(fscanf(fid, "%f", &temp) == 1)
                    input[j*data_rows+i] = (fp)temp;
            }
        }
    }
    fclose(fid);
}

