#include <stdio.h>
#include <sys/time.h>
#include <float.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <omp.h>

#define min( a, b )         a > b ? b : a
#define ceilDiv( a, b )     ( a + b - 1 ) / b
#define DEBUG               0

#define MAX_ARGS 10
#define REC_LENGTH 53
#define LATITUDE_POS 28
#define OPEN 10000

#ifdef TIMING
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;

static void tvsub(struct timeval *a, struct timeval *b, struct timeval *res) {
    res->tv_sec = a->tv_sec - b->tv_sec;
    res->tv_usec = a->tv_usec - b->tv_usec;
    if (res->tv_usec < 0) {
        res->tv_sec--;
        res->tv_usec += 1000000;
    }
}
#endif

typedef struct latLong
{
  float lat;
  float lng;
} LatLong;

typedef struct record
{
  char recString[REC_LENGTH];
  float distance;
} Record;

/* Dynamic arrays for records and locations */
Record *records = NULL;
LatLong *locations = NULL;
int recordsCapacity = 0;
int recordsCount = 0;

void ensureCapacity(int needed) {
    if (needed > recordsCapacity) {
        int newCap = recordsCapacity == 0 ? 1024 : recordsCapacity * 2;
        while (newCap < needed) newCap *= 2;
        records = (Record *)realloc(records, sizeof(Record) * newCap);
        locations = (LatLong *)realloc(locations, sizeof(LatLong) * newCap);
        recordsCapacity = newCap;
    }
}

int loadData(char *filename);
void findLowest(Record *records, float *distances, int numRecords, int topN);
void printUsage();
int parseCommandline(int argc, char *argv[], char* filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d);

int main(int argc, char* argv[])
{
    int    i=0;
    float lat, lng;
    int quiet=0, timing=0, platform=0, device=0;
    char filename[100];
    int resultsCount=10;

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

    /* parse command line */
    if (parseCommandline(argc, argv, filename, &resultsCount, &lat, &lng,
                     &quiet, &timing, &platform, &device)) {
      printUsage();
      return 0;
    }

    int numRecords = loadData(filename);
    if (numRecords < resultsCount) resultsCount = numRecords;

    /* Allocate distances array */
#ifdef TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif
    float *distances = (float *)malloc(sizeof(float) * numRecords);
#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    /* Compute Euclidean distances using OpenMP */
#ifdef TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    #pragma omp parallel for schedule(static)
    for (i = 0; i < numRecords; i++) {
        float dlat = lat - locations[i].lat;
        float dlng = lng - locations[i].lng;
        distances[i] = (float)sqrt(dlat * dlat + dlng * dlng);
    }

#ifdef TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    /* find the resultsCount least distances */
    findLowest(records, distances, numRecords, resultsCount);

    /* print out results */
    if (!quiet)
    for(i = 0; resultsCount > i; i++) {
      printf("%s --> Distance=%f\n", records[i].recString, records[i].distance);
    }

    free(distances);
    free(records);
    free(locations);

#ifdef TIMING
    gettimeofday(&tv_total_end, NULL);
    tvsub(&tv_total_end, &tv_total_start, &tv);
    total_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif

    return 0;
}

int loadData(char *filename) {
    FILE   *flist, *fp;
    int    i=0;
    char dbname[64];
    int recNum=0;

    flist = fopen(filename, "r");
    if (!flist) {
        fprintf(stderr, "error opening filelist\n");
        exit(1);
    }
    while(!feof(flist)) {
        if(fscanf(flist, "%s\n", dbname) != 1) {
            if (feof(flist)) break;
            fprintf(stderr, "error reading filelist\n");
            exit(0);
        }
        fp = fopen(dbname, "r");
        if(!fp) {
            printf("error opening a db\n");
            exit(1);
        }
        /* read each record */
        while(!feof(fp)){
            Record record;
            LatLong latLong;
            fgets(record.recString, 49, fp);
            fgetc(fp); /* newline */
            if (feof(fp)) break;

            /* parse for lat and long */
            char substr[6];

            for(i=0; 5 > i; i++) substr[i] = *(record.recString+i+28);
            substr[5] = '\0';
            latLong.lat = atof(substr);

            for(i=0; 5 > i; i++) substr[i] = *(record.recString+i+33);
            substr[5] = '\0';
            latLong.lng = atof(substr);

            ensureCapacity(recNum + 1);
            locations[recNum] = latLong;
            records[recNum] = record;
            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);
    return recNum;
}

void findLowest(Record *records, float *distances, int numRecords, int topN){
  int i, j;
  float val;
  int minLoc;
  Record tempRec;
  float tempDist;

  for(i=0; topN > i; i++) {
    minLoc = i;
    for(j=i; numRecords > j; j++) {
      val = distances[j];
      if (distances[minLoc] > val) minLoc = j;
    }
    /* swap locations and distances */
    tempRec = records[i];
    records[i] = records[minLoc];
    records[minLoc] = tempRec;

    tempDist = distances[i];
    distances[i] = distances[minLoc];
    distances[minLoc] = tempDist;

    /* add distance to the min we just found */
    records[i].distance = distances[i];
  }
}

